126	// CheckProcessRunning verifies that a named process is currently running on the host.
127	func CheckProcessRunning(name string) AssertionResult {
128		if name == "" {
129			return AssertionResult{Type: "process_running", Expected: name, Actual: "not found", Passed: false}
130		}
131		if runtime.GOOS == "windows" {
132			out, err := exec.Command("tasklist", "/FI", "IMAGENAME eq "+name+".exe").Output()
133			if err != nil || !strings.Contains(string(out), name) {
134				return AssertionResult{Type: "process_running", Expected: name, Actual: "not found", Passed: false}
